package com.weaone.themoa.domain.customerservice.rag;

import org.springframework.stereotype.Component;

import java.util.List;

@Component
public class CustomerServiceGuideCatalog {

    public List<CustomerKnowledgeDocument> documents() {
        return List.of(
                guide("service-scope", "고객센터 챗봇 답변 범위", "더모아 고객센터 챗봇은 서비스 사용법과 고객센터 운영 정책을 안내하는 용도로 제공된다. 답변 범위에는 카드 연동, 결제내역 동기화, 하루 권장 소비액, 고정지출, 수기 지출, 계정 보안, 청년정책 기능 사용법, 금융상품 추천 기능 사용법, FAQ가 포함된다. 챗봇은 실제 청년정책 추천 결과 생성, 금융상품 가입 판단, 개인 소비 데이터 분석, 외부 최신 정보 조회를 대신하지 않는다. 개인 계정 상태 확인이나 민감정보 확인이 필요한 문제는 1:1 문의에서 처리한다."),
                guide("policy-feature-start", "청년정책 추천 기능 사용 안내", "청년정책 추천은 대시보드의 정책 추천 화면에서 이용한다. 사용자는 지역, 나이, 재학 여부, 취업 상태, 지원받고 싶은 분야를 자연어로 입력할 수 있다. 지역 정보는 가입 단계에서 필수로 받지 않으며, 정책 추천 화면 첫 진입 또는 검색 과정에서 입력할 수 있다. 입력 조건이 구체적일수록 관련 정책을 찾기 쉽다."),
                guide("policy-region", "정책 추천 지역 정보 사용 기준", "지역 기반 청년정책 검색에서는 거주지 또는 근무지 지역 정보가 사용된다. 사용자가 지역을 명확히 입력하면 해당 지역과 호환되는 정책을 우선 조회한다. 지역이 불명확하면 추천 정확도가 낮아질 수 있으므로 시도 또는 시군구 단위의 지역을 추가로 입력하는 것이 좋다. 지역 정보는 정책 추천 정확도를 높이는 목적으로만 사용한다."),
                guide("policy-result", "정책 추천 결과 해석 기준", "정책 추천 결과는 더모아가 수집한 정책 데이터와 사용자가 입력한 검색 조건을 바탕으로 관련도가 높은 정책을 보여주는 참고 정보다. 최종 신청 가능 여부, 신청 기간, 제출 서류, 예산 소진 여부는 운영 기관의 공식 상세 페이지에서 확인해야 한다. 더모아의 추천 결과는 공식 기관의 심사 결과나 신청 가능 확정을 의미하지 않는다."),
                guide("policy-no-result", "정책 검색 결과 없음 안내", "정책 검색 결과가 없을 때는 조건을 넓혀 다시 검색할 수 있다. 지역을 시도 단위로 넓히거나 나이, 취업 상태, 지원 분야 조건을 덜 구체적으로 입력하면 더 많은 후보를 확인할 수 있다. 조건을 조정해도 결과가 없으면 현재 수집된 정책 데이터 안에서 관련 정책이 없을 수 있다."),
                guide("policy-profile", "정책 추천 조건 입력 예시", "정책 추천 정확도를 높이려면 나이, 지역, 재학 여부, 취업 상태, 지원 목적을 함께 입력하는 것이 좋다. 입력 예시는 '서울 사는 27살 취준생 주거 지원 정책', '부산 대학생 교통비 지원', '인천 청년 창업 지원금'처럼 작성할 수 있다. 너무 짧은 키워드만 입력하면 조건 해석이 제한될 수 있다."),
                guide("financial-feature-start", "금융상품 추천 기능 사용 안내", "금융상품 추천은 상품 추천 화면에서 이용한다. 예금, 적금, 대출, 연금 등 상품 조건을 비교할 수 있으며 사용자가 입력한 조건과 서비스 내 소비/예산 맥락을 참고해 후보를 보여줄 수 있다. 고객센터 챗봇은 금융상품 추천 기능의 사용 방법만 안내한다. 특정 상품 가입 권유나 개인별 투자 판단은 제공하지 않는다."),
                guide("financial-result", "금융상품 추천 결과 확인 기준", "금융상품 추천 결과는 참고용 정보다. 금리, 우대조건, 가입 가능 여부, 중도해지 조건, 세금, 수수료는 금융기관의 공식 상품 설명과 약관에서 최종 확인해야 한다. 더모아의 추천 결과는 금융기관의 심사 승인이나 수익 보장을 의미하지 않는다. 최신 금리 변동은 금융기관 공지에 따라 달라질 수 있다."),
                guide("daily-budget-formula", "하루 권장 소비액 계산 기준", "하루 권장 소비액은 월 예산에서 어제까지의 이번 급여주기 누적 순지출을 뺀 뒤, 오늘을 포함한 남은 일수로 나누어 계산한다. 월 예산은 월급에서 고정지출 합계와 월 저축 목표를 뺀 금액이다. 오늘 발생한 결제내역은 다음 계산 시점부터 반영되어 당일 권장액이 중간에 흔들리지 않도록 처리된다."),
                guide("salary-day-change", "급여일 변경 반영 기준", "급여일을 변경해도 이미 진행 중인 급여주기는 그대로 유지된다. 변경한 급여일은 다음 급여주기부터 적용된다. 이미 시작된 주기의 예산과 하루 권장액은 소급해서 다시 계산하지 않는다. 급여일을 바꾼 직후 화면의 권장액이 즉시 바뀌지 않는 것은 정상 동작이다."),
                guide("budget-change", "월급과 저축 목표 변경 반영 기준", "월급이나 저축 목표를 수정하면 이후 예산 계산에는 변경값이 반영된다. 이미 확정되어 표시된 오늘 하루 권장액은 중간에 바뀌지 않는다. 변경값은 다음 날 새 계산 시점부터 반영된다. 과거 지출 내역이나 이미 계산된 급여주기 전체가 자동으로 다시 계산되는 것은 아니다."),
                guide("surplus", "남은 예산 이월 기준", "급여주기가 끝났을 때 남은 예산은 다음 달로 자동 이월되지 않는다. 새 급여주기는 다시 월급 기준으로 계산된다. 남은 잉여금은 저축 또는 금융상품 추천을 살펴보는 참고 신호로 사용할 수 있다. 사용자가 별도로 저축하거나 지출 계획에 반영해야 한다."),
                guide("card-sync-start", "카드 연동 시작과 수집 기준", "카드 연동은 지원 카드사를 선택하고 카드사 인증을 거쳐 시작한다. 카드를 연결하면 카드 결제내역을 수집해 소비 내역 화면과 예산 계산에 반영한다. 카드사 점검, 인증 만료, 비밀번호 오류, 카드사 응답 지연이 있으면 수집이 늦어질 수 있다. 연동 이후에는 자동 수집으로 결제내역이 갱신된다."),
                guide("card-sync-initial-delay", "첫 카드동기화 3개월 결제내역 수집 시간", "첫 카드동기화는 회원가입 후 카드를 처음 연결하거나 카드 결제내역을 처음 가져오는 작업을 말한다. 더모아는 첫 카드동기화 시 서비스의 소비 분석 품질을 위해 최근 3개월치 카드 결제내역을 가져오도록 되어 있다. 수집할 결제내역이 많거나 카드사 응답이 느린 경우 적게는 3분, 많게는 5분 이상 걸릴 수 있다. 회원가입 직후 첫 카드동기화가 1분 넘게 끝나지 않는 상황은 초기 수집 중일 수 있다. 5분 이상 계속 멈춰 있거나 오류가 표시되면 1:1 문의에서 확인한다."),
                guide("card-sync-manual-delay", "수동 카드동기화 지연 기준", "수동 카드동기화는 이미 카드 연동과 초기 결제내역 수집이 완료된 사용자가 결제내역을 다시 불러오기 위해 직접 동기화를 실행하는 작업이다. 수동 카드동기화는 최근 3개월치 전체 내역을 새로 가져오는 절차가 아니다. 수동 카드동기화에서 1분 넘도록 동기화가 진행되지 않으면 더모아 쪽 오류일 수 있다. 이 경우 개인 계정 상태나 수집 작업 상태 확인이 필요하므로 1:1 문의에서 확인한다."),
                guide("card-sync-security", "카드 연동 보안 정책", "더모아 지원팀은 비밀번호, 카드사 원본 인증정보, 주민등록번호와 같은 민감정보를 고객센터 답변이나 챗봇 대화에서 요구하지 않는다. 카드사 로그인 자격증명은 카드 연결 과정에서만 사용된다. 1:1 문의를 남길 때도 민감정보 전체를 작성하지 않고 오류 화면, 발생 시간, 카드사명 등 문제 확인에 필요한 범위의 정보만 작성한다."),
                guide("card-sync-lock", "카드사 비밀번호 오류와 계정 잠금", "카드사 비밀번호를 여러 번 잘못 입력하면 더모아가 일시적으로 재시도를 제한하거나 카드사 계정이 잠길 수 있다. 카드사 쪽 계정 잠금은 더모아가 해제할 수 없다. 카드사 앱, 홈페이지, 고객센터에서 본인 인증 후 잠금을 해제해야 한다. 잠금 해제 후 다시 카드 연동을 시도할 수 있다."),
                guide("privacy-policy", "개인정보 처리방침 안내", "더모아는 서비스 제공에 필요한 범위에서 개인정보를 처리한다. 카드 연동, 소비 분석, 예산 계산, 고객센터 문의 처리를 위해 필요한 정보가 사용될 수 있다. 고객센터 챗봇은 비밀번호, 카드사 원본 인증정보, 주민등록번호 같은 민감정보 입력을 요구하지 않는다. 개인정보 처리방침의 적용 버전은 서비스 설정의 개인정보 처리방침 버전을 기준으로 관리된다."),
                guide("card-sync-supported-issuers", "지원 카드사 안내", "더모아 카드 연동은 지원 카드사 목록에 등록된 카드사만 사용할 수 있다. 현재 지원 대상에는 KB국민카드, 현대카드, 삼성카드, NH농협카드, BC카드, 신한카드, 우리카드, 롯데카드, 하나카드, 전북카드가 포함된다. 지원 목록에 없는 카드사는 카드 연동 화면에서 선택할 수 없으며, 수기 지출 입력으로 지출을 관리할 수 있다."),
                guide("card-sync-all-cards", "카드사 계정 내 복수 카드 수집 기준", "카드 연동은 카드사 계정 단위로 진행된다. 한 카드사 계정에 신용카드와 체크카드가 여러 장 연결되어 있으면 사용자가 카드를 한 장씩 고르는 방식이 아니라 해당 계정에서 조회되는 결제내역을 함께 수집한다. 특정 카드만 제외하는 기능은 별도 정책이 필요하다."),
                guide("card-sync-no-transaction", "연동 후 결제내역이 비어 있는 경우", "카드 연동에 성공했는데 결제내역이 보이지 않는 경우 실제 조회 기간 안에 승인 내역이 없거나 카드사 응답이 지연된 상태일 수 있다. 첫 카드동기화는 최근 3개월치 결제내역을 수집하며, 결제내역이 많은 경우 3분에서 5분 이상 걸릴 수 있다. 시간이 지나도 비어 있으면 카드사명, 연동 시각, 화면 상태를 1:1 문의에 남겨 확인한다."),
                guide("card-sync-refresh", "결제내역 새로고침 기준", "결제내역 새로고침은 카드사에서 최근 승인 내역을 다시 조회하는 작업이다. 카드사 점검 시간, 인증 만료, 네트워크 지연이 있으면 새로고침이 즉시 끝나지 않을 수 있다. 수동 새로고침이 1분 넘게 진행되지 않거나 반복 실패하면 더모아 쪽 수집 작업 상태 확인이 필요할 수 있으므로 1:1 문의에서 확인한다."),
                guide("card-sync-cancel-refund", "취소와 환불 내역 반영 기준", "카드 결제 취소와 환불 내역은 카드사 승인 데이터가 갱신된 뒤 더모아 결제내역에 반영된다. 카드사마다 취소 승인 또는 매입 취소가 표시되는 시간이 다를 수 있다. 취소 직후 더모아 화면에 원 결제가 바로 사라지지 않을 수 있으며, 다음 수집 시점 이후에도 반영되지 않으면 1:1 문의에서 확인한다."),
                guide("card-sync-duplicate", "결제내역 중복 표시 기준", "결제내역이 중복으로 보이는 경우 카드사 승인번호, 승인일시, 금액, 가맹점명이 같은지 확인해야 한다. 더모아는 카드사에서 내려온 승인정보를 기준으로 중복 수집을 방지한다. 같은 금액이 여러 번 결제된 실제 거래와 중복 수집 오류는 구분이 필요하므로 중복 의심 건은 결제일시와 금액을 1:1 문의에 남겨 확인한다."),
                guide("transaction-display-delay", "방금 결제한 내역 표시 시점", "방금 결제한 카드 내역은 카드사 승인 데이터가 조회 가능한 상태가 된 뒤 더모아에 표시된다. 결제 직후 즉시 표시되지 않는 것은 정상일 수 있다. 앱 진입 또는 수동 새로고침 시 최근 내역을 다시 확인할 수 있으며, 계속 누락되면 카드사 응답 지연이나 수집 오류 여부를 확인한다."),
                guide("transaction-category", "결제내역 카테고리 분류 기준", "결제내역 카테고리는 카드사에서 제공하는 업종 정보, 가맹점명, 더모아의 카테고리 규칙을 참고해 분류된다. 편의점, 카페, 교통, 배달, 쇼핑, 구독 등 대표 카테고리로 표시될 수 있다. 분류가 실제 지출 목적과 다르면 사용자가 화면에서 확인하거나 정정할 수 있는 정책이 필요하다."),
                guide("transaction-manual-cash", "현금과 계좌이체 지출 관리 기준", "현금과 계좌이체 지출은 카드사 자동 수집 대상이 아니다. 사용자는 수기 지출 입력 기능으로 현금과 계좌이체 지출을 직접 기록할 수 있다. 카드 지출과 달리 자동으로 들어오지 않으므로 예산 정확도를 높이려면 사용자가 빠짐없이 입력해야 한다."),
                guide("transaction-manual-card-limit", "카드 지출 수기 입력 제한 기준", "카드 자동수집이 켜져 있는 동안에는 카드 결제 수기 입력이 제한될 수 있다. 이는 같은 카드 결제내역이 자동 수집과 수기 입력으로 중복 집계되는 것을 막기 위한 정책이다. 카드 자동수집을 끈 상태에서는 카드 지출을 수기로 입력할 수 있지만, 기존 자동 수집 내역은 보존된다."),
                guide("transaction-manual-replacement", "수기 카드 지출 정본 대체 기준", "카드 연동 전에 수기로 입력한 카드 지출이 있고 이후 실제 카드 결제내역이 수집되면, 날짜와 금액 등 기준이 일치하는 수기 내역은 카드사에서 수집된 정본 내역으로 대체될 수 있다. 이 처리는 지출이 두 번 합산되는 것을 방지하기 위한 것이다."),
                guide("daily-budget-reflect-tomorrow", "오늘 결제내역의 하루 권장액 반영 시점", "오늘 발생한 결제내역은 당일 표시 중인 하루 권장 소비액을 즉시 바꾸지 않는다. 더모아는 하루 권장액이 하루 중 계속 흔들리지 않도록 다음 계산 시점부터 오늘 결제내역을 반영한다. 따라서 오늘 많이 썼더라도 현재 표시된 권장액이 즉시 줄지 않는 것은 정상 동작이다."),
                guide("daily-budget-overrun", "하루 권장액 초과 사용 기준", "하루 권장 소비액을 초과해 지출하면 남은 급여주기의 권장 소비액이 다음 계산 시점부터 낮아질 수 있다. 하루 권장액은 지출을 강제로 막는 한도가 아니라 소비 페이스를 보여주는 참고 기준이다. 초과 지출 자체가 오류는 아니며 다음 날 이후 예산 계산에 반영된다."),
                guide("daily-budget-negative", "남은 예산이 부족한 경우", "급여주기 누적 순지출이 월 예산을 초과하면 남은 예산이 0원 이하로 표시될 수 있다. 이 경우 하루 권장 소비액은 매우 낮거나 0원에 가깝게 계산될 수 있다. 다음 급여주기가 시작되면 월급 기준으로 새 예산이 다시 계산된다."),
                guide("fixed-expense-not-detected", "고정지출 후보가 안 보이는 경우", "고정지출 후보는 최근 3개월 내 반복 결제 패턴이 충분히 확인되어야 추천된다. 같은 가맹점에서 3회 이상, 매달 비슷한 날짜와 유사한 금액으로 결제된 내역이 부족하면 후보가 나타나지 않을 수 있다. 카드 첫 연동 직후에는 데이터가 아직 충분하지 않아 추천이 늦게 보일 수 있다."),
                guide("fixed-expense-due-alert", "고정지출 미납 알림 기준", "등록된 고정지출의 예상 결제일이 지났는데 실제 카드 결제내역과 매칭되지 않으면 미납 또는 누락 가능성을 알림으로 보여줄 수 있다. 가맹점 표기 차이, 결제일 변경, 결제 금액 변경이 있으면 자동 매칭이 실패할 수 있다. 사용자는 고정지출 화면에서 결제 여부를 확인한다."),
                guide("fixed-expense-price-change", "고정지출 금액 변경 감지 기준", "등록된 고정지출과 매칭되는 실제 결제 금액이 기존 금액과 크게 달라지면 금액 변경 가능성이 있다. 국내 결제는 유사 금액 범위를 벗어나는 경우 사용자가 등록 금액을 업데이트해야 예산 계산이 더 정확해진다. 해외 구독은 환율과 수수료 때문에 원화 금액이 달라질 수 있다."),
                guide("fixed-expense-foreign-subscription", "해외 구독 결제 금액 안내", "해외 구독 결제는 카드사 환율과 해외이용수수료가 반영되어 실제 원화 청구액이 달라질 수 있다. 같은 달러 금액이라도 결제일 환율에 따라 더모아에 표시되는 원화 금액과 사용자가 예상한 금액이 다를 수 있다. 차이가 계속 크면 고정지출 등록 금액을 실제 청구 금액에 맞춰 조정한다."),
                guide("faq-search", "일반검색과 챗봇 검색 차이", "고객센터 일반검색은 FAQ 목록에서 키워드와 카테고리 기준으로 관련 질문을 찾는 기능이다. 챗봇 검색은 FAQ, 사용가이드, 기존 관리자 답변을 함께 검색해 질문에 대한 자연어 답변을 생성한다. 정확한 기존 FAQ를 직접 보고 싶으면 일반검색을 사용하고, 상황 설명형 질문은 챗봇 검색을 사용할 수 있다."),
                guide("faq-feedback", "FAQ 도움됨 피드백 기준", "FAQ 도움됨 또는 도움되지 않음 피드백은 사용자가 해당 FAQ가 문제 해결에 도움이 되었는지 표시하는 기능이다. 같은 사용자의 같은 FAQ 피드백은 중복 집계되지 않도록 멱등하게 처리된다. 피드백은 FAQ 품질 개선에 참고할 수 있다."),
                guide("inquiry-create", "1:1 문의 접수 기준", "1:1 문의는 FAQ와 챗봇으로 해결되지 않거나 개인 계정 상태 확인이 필요한 문제를 접수하는 기능이다. 문의에는 발생한 화면, 오류 메시지, 발생 시각, 사용한 카드사나 기능명을 포함하면 확인이 빠르다. 비밀번호, 카드사 원본 인증정보, 주민등록번호 전체와 같은 민감정보는 작성하지 않는다."),
                guide("inquiry-attachment", "1:1 문의 첨부파일 기준", "1:1 문의에는 문제 확인을 위한 이미지 파일을 첨부할 수 있다. 첨부파일은 PNG 또는 JPEG 이미지로 제한되며 파일당 10MB, 문의당 최대 3개까지 허용된다. 서버에는 공개 URL이 아니라 내부 object key로 저장하고, 인증된 사용자만 본인 문의 첨부파일을 내려받을 수 있다."),
                guide("inquiry-answer-notification", "문의 답변 알림 기준", "관리자가 1:1 문의에 최초 답변을 등록하면 문의 작성자에게 앱 알림이 생성된다. 같은 문의에 대해 답변 알림이 중복 생성되지 않도록 고유 키 기준으로 한 번만 생성한다. 사용자는 앱 내 알림을 통해 답변 등록 여부를 확인할 수 있다."),
                guide("inquiry-admin-answer", "관리자 답변 처리 기준", "관리자 답변은 문의당 하나의 답변으로 관리된다. 답변 내용은 CommonMark 형식의 Markdown 원문으로 저장하며 raw HTML은 허용하지 않는다. 답변 수정 시에는 동시 수정 충돌을 막기 위해 버전 정보를 기준으로 검증한다."),
                guide("account-login-lock", "더모아 로그인 잠금 기준", "더모아 로그인 비밀번호를 여러 번 잘못 입력하면 계정 보호를 위해 일정 시간 로그인이 제한될 수 있다. 이 제한은 더모아 계정 로그인에 대한 것이며 카드사 계정 잠금과는 별개다. 카드사 계정 잠금은 카드사 앱이나 고객센터에서 본인 인증 후 해제해야 한다."),
                guide("account-session", "기기별 로그아웃 기준", "일반 로그아웃은 현재 사용 중인 기기의 세션만 종료한다. 다른 기기에 로그인된 상태는 유지될 수 있다. 모든 기기에서 로그아웃해야 하는 상황에서는 비밀번호 변경을 통해 기존 세션을 무효화한다."),
                guide("policy-official-check", "청년정책 공식 확인 기준", "더모아의 청년정책 검색 결과는 참고 정보이며 공식 기관의 신청 가능 확정이 아니다. 신청 기간, 대상 조건, 제출 서류, 예산 소진 여부는 정책 운영 기관의 공식 상세 페이지에서 확인해야 한다. 챗봇은 특정 사용자가 실제로 선정될지 판단하지 않는다."),
                guide("financial-official-check", "금융상품 공식 확인 기준", "더모아의 금융상품 추천 결과는 참고 정보이며 가입 승인, 수익 보장, 최저 금리 보장을 의미하지 않는다. 금리, 우대조건, 수수료, 세금, 중도해지 조건은 금융기관의 공식 상품 설명과 약관에서 확인해야 한다. 챗봇은 사용자의 가입 결정을 대신하지 않는다."),
                guide("fixed-expense-detect", "고정지출 자동 추천 기준", "고정지출은 같은 가맹점에서 최근 3개월 내 3회 이상, 매달 비슷한 날짜 주기, 유사한 금액으로 결제된 내역이 있을 때 후보로 추천될 수 있다. 카드 연동 직후에는 판단할 데이터가 부족해 추천이 바로 나오지 않을 수 있다. 결제내역이 충분히 쌓이면 고정지출 후보가 더 정확해진다."),
                guide("fixed-expense-matching", "고정지출 이중 차감 방지", "등록된 고정지출과 실제 카드 결제내역이 매칭되면 하루 지출 합계에서 중복 차감되지 않도록 처리한다. 가맹점 표기가 다르거나 금액 차이가 큰 경우 매칭이 실패할 수 있다. 매칭이 잘못되었거나 누락된 경우 고정지출 화면에서 정정할 수 있다."),
                guide("manual-expense", "수기 지출 입력 기준", "현금과 계좌이체 지출은 카드사 자동 수집 대상이 아니므로 수기로 입력할 수 있다. 카드 자동수집이 켜져 있는 동안에는 중복 방지를 위해 카드 결제 수기 입력이 제한될 수 있다. 카드 연동 후 실제 카드 결제내역과 일치하는 수기 카드 지출은 정본 내역으로 대체될 수 있다."),
                guide("account-password", "비밀번호 변경과 로그아웃 기준", "비밀번호를 변경하면 계정 보안을 위해 접속 중이던 모든 기기에서 강제 로그아웃된다. 일반 로그아웃은 현재 기기의 세션만 종료한다. 분실 또는 도용이 의심되면 비밀번호를 변경해 모든 세션을 종료하는 것이 좋다."),
                guide("account-delete", "회원 탈퇴 기준", "회원 탈퇴 시 등록된 카드사 연결 정보는 즉시 파기되고 자동 수집 대상에서 제외된다. 탈퇴 이후 계정과 연결 정보 복구는 어려울 수 있다. 필요한 결제내역이나 문의 기록은 탈퇴 전에 확인하는 것이 좋다."),
                guide("inquiry-handoff", "1:1 문의 처리 기준", "챗봇이 고객센터 지식 문서에서 충분한 근거를 찾지 못한 문제는 1:1 문의에서 처리한다. 사용자 개인 계정 상태 확인, 카드 연동 실패 원인 확인, 결제내역 정정, 수집 작업 상태 확인, 민감정보 확인이 필요한 문제는 챗봇이 추측해서 답변하지 않는다. 1:1 문의에는 발생 화면, 오류 메시지, 발생 시간, 사용한 기능을 함께 남기면 확인에 도움이 된다.")
        );
    }

    private CustomerKnowledgeDocument guide(String id, String title, String content) {
        return new CustomerKnowledgeDocument("guide:" + id, CustomerKnowledgeSourceType.GUIDE,
                id, "사용가이드", title, content);
    }
}
